#include<bits/stdc++.h>
using namespace std;
long long tot,val[10010],u[10010],v[10010],w[10010];
struct matrix
{
    long long a[210][210];
    matrix()
    {
        memset(a,0x3f,sizeof(a));
    }
    friend matrix operator*(const matrix&a,const matrix&b)
    {
        matrix c;
        for(long long i=1;i<=tot;i++)
        {
            for(long long j=1;j<=tot;j++)
            {
                for(long long k=1;k<=tot;k++)
                {
                    c.a[i][j]=min(c.a[i][j],a.a[i][k]+b.a[k][j]);
                }
            }
        }
        return c;
    }
}base,ans;
void fastpow(long long y)
{
    ans=base;
    y--;
    while(y)
    {
        if(y%2==1)
        {
            ans=ans*base;
        }
        base=base*base;
        y/=2;
    }
}
int main()
{
    int n,t,s,e;
    scanf("%d%d%d%d",&n,&t,&s,&e);
    for(int i=1;i<=t;i++)
    {
        scanf("%d%d%d",&w[i],&u[i],&v[i]);
        val[++tot]=u[i];
        val[++tot]=v[i];
    }
    sort(val+1,val+1+tot);
    tot=unique(val+1,val+1+tot)-val-1;
    for(int i=1;i<=t;i++)
    {
        u[i]=lower_bound(val+1,val+1+tot,u[i])-val;
        v[i]=lower_bound(val+1,val+1+tot,v[i])-val;
        base.a[u[i]][v[i]]=base.a[v[i]][u[i]]=w[i];
    }
    fastpow(n);
    s=lower_bound(val+1,val+1+tot,s)-val;
    e=lower_bound(val+1,val+1+tot,e)-val;
    printf("%lld",ans.a[s][e]);
    return 0;
}
